import"./ticker-BxUDbM2L.js";import{i as e}from"./country-page-CK6BdUjw.js";import"./utils-Owvk3OYq.js";import"./breadcrumbs-CxxVGuAV.js";e({countryCode:"AE",currency:"AED",flag:"🇦🇪",nameEn:"United Arab Emirates",nameAr:"الإمارات العربية المتحدة",fixedPeg:!0,decimals:2,timezone:"Asia/Dubai",relatedCountries:[{file:"saudi-arabia.html",nameEn:"Saudi Arabia",nameAr:"السعودية",flag:"🇸🇦"},{file:"kuwait.html",nameEn:"Kuwait",nameAr:"الكويت",flag:"🇰🇼"},{file:"qatar.html",nameEn:"Qatar",nameAr:"قطر",flag:"🇶🇦"},{file:"bahrain.html",nameEn:"Bahrain",nameAr:"البحرين",flag:"🇧🇭"},{file:"oman.html",nameEn:"Oman",nameAr:"عُمان",flag:"🇴🇲"},{file:"india.html",nameEn:"India",nameAr:"الهند",flag:"🇮🇳"}],faqEn:[{q:"What is today's gold price in UAE (AED per gram)?",a:"The live 22K gold price in UAE is updated every 90 seconds based on the global XAU/USD spot rate and the UAE Dirham's fixed peg of 3.6725 to the US Dollar. Check the price card above for the current rate."},{q:"Why is the UAE Dirham pegged to the US Dollar?",a:"The UAE Central Bank has maintained a fixed exchange rate of 3.6725 AED per USD since 1997. This peg provides monetary stability and means AED gold prices move in direct proportion to global USD gold prices."},{q:"What is the most popular karat for gold in the UAE?",a:"22K gold is the most popular for jewellery in the UAE, especially in the Dubai Gold Souk. 24K is used for investment bars and coins, while 21K and 18K are common for fine jewellery."},{q:"How is the gold price calculated?",a:"The price is calculated using the live XAU/USD spot rate from gold-api.com, divided by 31.1035 (grams per troy oz), multiplied by the karat purity fraction, then converted to AED using the fixed peg rate of 3.6725."},{q:"Is the Dubai Gold Souk price the same as the spot price?",a:"Retail prices at the Gold Souk typically include a making charge (labour fee) of 3–25 AED per gram depending on the design, in addition to the spot gold price. Our prices show the raw spot equivalent only."}],faqAr:[{q:"ما هو سعر الذهب اليوم في الإمارات (درهم للغرام)؟",a:"يتم تحديث سعر ذهب عيار 22 في الإمارات كل 90 ثانية بناءً على سعر XAU/USD العالمي وربط الدرهم الثابت بالدولار (3.6725). تحقق من بطاقة السعر أعلاه للحصول على السعر الحالي."},{q:"لماذا يرتبط الدرهم الإماراتي بالدولار الأمريكي؟",a:"يحافظ المصرف المركزي الإماراتي على سعر صرف ثابت منذ عام 1997، وهو 3.6725 درهم لكل دولار. يوفر هذا الربط استقراراً نقدياً ويعني أن أسعار الذهب بالدرهم تتحرك بنسبة مباشرة مع أسعار الذهب العالمية."},{q:"ما هو العيار الأكثر شيوعاً للذهب في الإمارات؟",a:"يُعد عيار 22 الأكثر شيوعاً للمجوهرات في الإمارات، خاصةً في سوق الذهب بدبي. يستخدم عيار 24 للسبائك والعملات الاستثمارية، بينما يشيع عيار 21 و18 للمجوهرات الدقيقة."},{q:"كيف يتم احتساب سعر الذهب؟",a:"يتم الحساب باستخدام سعر XAU/USD الفوري من gold-api.com، مقسوماً على 31.1035 (غرام في الأوقية)، مضروباً في نسبة نقاء العيار، ثم محولاً إلى درهم باستخدام سعر الربط الثابت 3.6725."},{q:"هل سعر سوق الذهب في دبي هو نفس السعر الفوري؟",a:"تشمل أسعار التجزئة في سوق الذهب عادةً رسوم الصنعة (3–25 درهم للغرام حسب التصميم) إضافةً إلى سعر الذهب الفوري. تعرض أسعارنا السعر الفوري الصافي فقط."}]});
